@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(silent=True) or {}
    name = payload.get("name")
    if not name:
        return jsonify(error="name is required"), 400

    with capture_span("sql_insert_item", span_type="db", span_subtype="sql", span_action="query"):
        with engine.begin() as conn:
            conn.execute(
                text("INSERT INTO items (name, created_at) VALUES (:name, :created_at)"),
                {"name": name, "created_at": time.time()},
            )

    with capture_span("sql_select_last_item", span_type="db", span_subtype="sql", span_action="query"):
        with engine.connect() as conn:
            row = conn.execute(text("SELECT id, name, created_at FROM items ORDER BY id DESC LIMIT 1")).mappings().first()

    return jsonify(item=dict(row))

@app.route("/items", methods=["GET"])
def list_items():
    limit = int(request.args.get("limit", "50"))
    limit = max(1, min(limit, 500))

    with capture_span("sql_list_items", span_type="db", span_subtype="sql", span_action="query"):
        with engine.connect() as conn:
            rows = conn.execute(
                text("SELECT id, name, created_at FROM items ORDER BY id DESC LIMIT :limit"),
                {"limit": limit},
            ).mappings().all()

    return jsonify(items=[dict(r) for r in rows])

